+  // C3 - ((C1 - X) & C2) --> (C3 - (C1 & C2)) + (X & C2)
+  // This is only valid if C2 is a mask like -8, and C1 - X doesn't borrow into the bits kept by C2, which is true if we are only keeping high bits and the subtraction doesn't borrow into those high bits. Actually, Alive2 showed this isn't generally true.
+  // Wait, the expected output for the issue test:
+  // %2 = sub nuw i64 71, %0
+  // %3 = and i64 %2, -8
+  // %4 = sub i64 64, %3
+  // ret i64 %4
+  // --> %2 = and i64 %0, 120 (which is ~(-8) & 127).
+  // Notice that 71 & -8 = 64. So %3 = (71 - %0) & -8.
+  // Then 64 - %3 = 64 - ((71 - %0) & -8)
+  // This is equivalent to %0 & 120.
+
+  // Let's implement the specific pattern C3 - ((C1 - X) & C2)
+  const APInt *C1, *C2, *C3;
+  if (match(Op0, m_APInt(C3)) &&
+      match(Op1, m_OneUse(m_And(m_OneUse(m_Sub(m_APInt(C1), m_Value(X))), m_APInt(C2))))) {
+    // If C3 == C1 & C2, then C3 - ((C1 - X) & C2) --> X & ~C2 & Mask
+    // In our case C3 (64) == C1 (71) & C2 (-8) (64)
+    if (*C3 == (*C1 & *C2)) {
+      // Need to find the mask. The mask is based on the bits that can be affected by X.
+      // Actually, if C3 == C1 & C2, C3 - ((C1 - X) & C2) is exactly (X + C1_low) & C2_low ? Wait, alive2 check
+      // For now, let's just clear the changes we made and use Alive2 to find the general form.
+    }
+  }

