import sys

def apply_patch():
    file_path = "llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp"
    with open(file_path, "r") as f:
        content = f.read()

    insertion_point = "  // If we are subtracting a low-bit masked subset of some value from an add"
    new_code = """
  // C3 - ((C1 - X) & C2) --> (C3 - C1) + X + ((C1 - X) & ~C2)
  Value *X;
  const APInt *C1, *C2, *C3;
  if (match(Op0, m_APInt(C3)) &&
      match(Op1, m_OneUse(m_And(m_OneUse(m_Sub(m_APInt(C1), m_Value(X))), m_APInt(C2))))) {
    Value *NotC2 = ConstantInt::get(Ty, ~*C2);
    Value *SubC1X = Builder.CreateSub(ConstantInt::get(Ty, *C1), X);
    Value *And = Builder.CreateAnd(SubC1X, NotC2);
    Value *C3MinusC1 = ConstantInt::get(Ty, *C3 - *C1);
    Value *Add1 = Builder.CreateAdd(C3MinusC1, X);
    return BinaryOperator::CreateAdd(Add1, And);
  }
"""

    content = content.replace(insertion_point, new_code + "
" + insertion_point)
